class Solution {
public:
    int calculateNetworkDelayTime(
        vector<vector<int>>& travelTimes,
        int totalNodes,
        int startNode
    ) {
        vector<vector<pair<int,int>>> graph(totalNodes + 1);

        for (auto &e : travelTimes) {
            graph[e[0]].push_back({e[1], e[2]});
        }

        vector<int> dist(totalNodes + 1, INT_MAX);
        priority_queue<pair<int,int>, vector<pair<int,int>>, greater<pair<int,int>>> pq;

        dist[startNode] = 0;
        pq.push({0, startNode});

        while (!pq.empty()) {
            auto [time, node] = pq.top();
            pq.pop();

            if (time > dist[node]) continue;

            for (auto &nbr : graph[node]) {
                int next = nbr.first;
                int w = nbr.second;

                if (dist[next] > time + w) {
                    dist[next] = time + w;
                    pq.push({dist[next], next});
                }
            }
        }

        int ans = 0;
        for (int i = 1; i <= totalNodes; i++) {
            if (dist[i] == INT_MAX) return -1;
            ans = max(ans, dist[i]);
        }
        return ans;
    }
};

