int calculateNetworkDelayTime(
    int travelTimes[][3],
    int edges,
    int totalNodes,
    int startNode
) {
    int graph[101][101];

    for (int i = 1; i <= totalNodes; i++) {
        for (int j = 1; j <= totalNodes; j++) {
            graph[i][j] = INT_MAX;
        }
    }

    for (int i = 0; i < edges; i++) {
        int u = travelTimes[i][0];
        int v = travelTimes[i][1];
        int w = travelTimes[i][2];

        graph[u][v] = w;
    }

    int dist[101];
    int vis[101];

    for (int i = 1; i <= totalNodes; i++) {
        dist[i] = INT_MAX;
        vis[i] = 0;
    }

    dist[startNode] = 0;

    for (int cnt = 1; cnt <= totalNodes; cnt++) {

        int u = -1;
        int mn = INT_MAX;

        for (int i = 1; i <= totalNodes; i++) {
            if (!vis[i] && dist[i] < mn) {
                mn = dist[i];
                u = i;
            }
        }

        if (u == -1)
            break;

        vis[u] = 1;

        for (int v = 1; v <= totalNodes; v++) {

            if (graph[u][v] == INT_MAX)
                continue;

            if (dist[u] != INT_MAX &&
                dist[u] + graph[u][v] < dist[v]) {

                dist[v] = dist[u] + graph[u][v];
            }
        }
    }

    int ans = 0;

    for (int i = 1; i <= totalNodes; i++) {

        if (dist[i] == INT_MAX)
            return -1;

        if (dist[i] > ans)
            ans = dist[i];
    }

    return ans;
}

