class Solution {
    calculateNetworkDelayTime(travelTimes, totalNodes, startNode) {
        // Build adjacency list
        const graph = Array.from({ length: totalNodes + 1 }, () => []);

        for (const [u, v, t] of travelTimes) {
            graph[u].push([v, t]);
        }

        // Dijkstra
        const dist = Array(totalNodes + 1).fill(Infinity);
        dist[startNode] = 0;

        // Min-heap implementation
        const pq = [];
        const push = (item) => {
            pq.push(item);
            let i = pq.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (pq[p][0] <= pq[i][0]) break;
                [pq[p], pq[i]] = [pq[i], pq[p]];
                i = p;
            }
        };

        const pop = () => {
            const root = pq[0];
            const last = pq.pop();
            if (pq.length > 0) {
                pq[0] = last;
                let i = 0;
                while (true) {
                    let l = 2 * i + 1;
                    let r = 2 * i + 2;
                    let smallest = i;

                    if (l < pq.length && pq[l][0] < pq[smallest][0]) smallest = l;
                    if (r < pq.length && pq[r][0] < pq[smallest][0]) smallest = r;

                    if (smallest === i) break;
                    [pq[i], pq[smallest]] = [pq[smallest], pq[i]];
                    i = smallest;
                }
            }
            return root;
        };

        push([0, startNode]);

        while (pq.length > 0) {
            const [time, node] = pop();
            if (time > dist[node]) continue;

            for (const [next, w] of graph[node]) {
                if (dist[next] > time + w) {
                    dist[next] = time + w;
                    push([dist[next], next]);
                }
            }
        }

        let ans = 0;
        for (let i = 1; i <= totalNodes; i++) {
            if (dist[i] === Infinity) return -1;
            ans = Math.max(ans, dist[i]);
        }
        return ans;
    }
}
